import{z as t}from"zod";export const MusicGenProviderSchema=t.enum(["yunwu","custom"]),MusicGenConfigSchema=t.object({provider:MusicGenProviderSchema.default("yunwu"),model:t.string().default("chirp-v4"),apiKey:t.string().default(""),baseUrl:t.string().default("https://yunwu.ai"),instrumental:t.boolean().default(!1)}),MusicGenRequestSchema=t.object({prompt:t.string().optional(),lyrics:t.string().optional(),style:t.string().optional(),instrumental:t.boolean().optional(),title:t.string().optional(),descriptionPrompt:t.string().optional()}).refine(i=>i.prompt||i.descriptionPrompt||i.lyrics,{message:"prompt, lyrics, \u6216 descriptionPrompt \u81F3\u5C11\u9700\u8981\u63D0\u4F9B\u4E00\u4E2A"}),MUSIC_PROVIDER_CONFIGS=[{id:"yunwu",name:"\u4E91\u96FE (Yunwu) \u2014 Suno",baseUrl:"https://yunwu.ai",models:[{id:"chirp-v3-0",name:"Suno V3.0"},{id:"chirp-v3-5",name:"Suno V3.5"},{id:"chirp-v4",name:"Suno V4"},{id:"chirp-auk",name:"Suno V4.5 (Auk)"},{id:"chirp-v5",name:"Suno V5"},{id:"chirp-fenix",name:"Suno V5.5 (Fenix)"}]},{id:"custom",name:"\u81EA\u5B9A\u4E49 (Custom)",baseUrl:"",apiKeyOptional:!0,models:[]}];export class MusicProviderRegistry{table;constructor(e){const o=new Map;for(const n of e)o.set(n.id,n);this.table=o}get(e){return this.table.get(e)}has(e){return this.table.has(e)}list(){return Array.from(this.table.values())}defaultModel(e){return this.table.get(e)?.models[0]?.id}}export const musicProviderRegistry=new MusicProviderRegistry(MUSIC_PROVIDER_CONFIGS);
